use gif_editor_lib::export::{
    ExportFormat, ExportSettings, export_gif, export_image, export_video, ffmpeg_available,
};
use gif_editor_lib::gif_decoder::GifData;
use gif_editor_lib::layer::{ImageLayer, Layer, TextLayer};
use image::ImageReader;
use std::path::PathBuf;

fn fixture_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("fixtures")
        .join("test.gif")
}

// The test.gif fixture was already generated by gif_decoder_test.
// If it doesn't exist, generate it:
fn ensure_test_gif() {
    let path = fixture_path();
    if path.exists() {
        return;
    }
    std::fs::create_dir_all(path.parent().unwrap()).unwrap();
    let mut encoder =
        gif::Encoder::new(std::fs::File::create(&path).unwrap(), 10, 10, &[]).unwrap();
    encoder.set_repeat(gif::Repeat::Infinite).unwrap();
    for i in 0u8..3 {
        let pixels: Vec<u8> = (0..100).flat_map(|_| [i * 80, 0, 0, 255]).collect();
        let mut frame = gif::Frame::from_rgba(10, 10, &mut pixels.clone());
        frame.delay = 10;
        encoder.write_frame(&frame).unwrap();
    }
}

#[test]
fn export_gif_produces_valid_file() {
    ensure_test_gif();
    let mut gif = GifData::open(&fixture_path()).unwrap();
    let output = tempfile::NamedTempFile::new().unwrap();
    let output_path = output.path().with_extension("gif");
    let settings = ExportSettings {
        format: ExportFormat::Gif,
        quality: 80,
        resize: None,
        frame_index: None,
    };
    let frame_count = gif.frame_count();
    let frame_indices: Vec<usize> = (0..frame_count).collect();
    let delays: Vec<u16> = gif.delays().to_vec();
    export_gif(
        &mut gif,
        &[],
        &settings,
        &output_path,
        &frame_indices,
        &delays,
        |_| {},
    )
    .unwrap();
    let result = GifData::open(&output_path).unwrap();
    assert_eq!(result.frame_count(), 3);
    assert_eq!(result.dimensions(), (10, 10));
}

